                                      0x6B, 0x1A, 0x6B, 0x1A]
        
        
        let ROM1_Start = 0x1C00
        
        for a in 0..<ROM_Part_1.count
        {
            MEMORY[ROM1_Start + a].cell = ROM_Part_1[a]
            MEMORY[ROM1_Start + a].ROM = true
        }
        
        let ROM2_Start = 0x1800
        
        for a in 0..<ROM_Part_2.count
        {
            MEMORY[ROM2_Start + a].cell = ROM_Part_2[a]
            MEMORY[ROM2_Start + a].ROM = true
        }
        
    }
    
    
    func LoadFromTape(software : String)
    {
        if software == "Basic"
        {
            // print("Load MS Basic 00F1 00. 4065 G")
            // print("Load MS Basic 4065 A2 <space> G, then Return at the memory prompt, 40 at the character width and Y.")
            LoadBasic()
            MEMORY[0x26e4].cell = 0 // Magic fix for the BREAK issue
            
            
        }
        
        if software == "TinyBasic"
        {
            //print("Load Tiny Basic 2000  G")
            LoadTinyBasic()
            
        }
        
        if software == "VTL"
        {
            LoadVTL()
        }
        
        if software == "APPBASIC"
        {
            LoadAPPBASIC()
        }
        
        if software == "Forth"
        {
            //print("Load Forth 2300 G")
            LoadForth1()
        }
        
        if software == "PAL1ROM"
        {
            LoadPALrom()
        }
        
        if software == "JMON"
        {

            LoadJMON()
        }
        
        
        return
        
    }
    
    
    
    
    func loadHex(input : String)
    {
        let address = 0x2000
        let number_of_bytes = input.count/2
        for pair in 0..<number_of_bytes
        {
            let start = input.index(input.startIndex, offsetBy: ((pair * 2)))
            let end = input.index(input.startIndex, offsetBy: 1+(pair * 2))
            let range = start..<end
            let pairH = input[range]
            let pairD = UInt8((pairH), radix: 16)!
            WriteAddress(address: UInt16(address + pair), value: pairD)
            
        }
        
        //print("Loaded TinyBasic to 0x2000")
    }
    
    func getHexStringFromMemory(startAddress : Int, dataLength : Int) -> String {
        
       // print("From ", startAddress)
       // print("Lengh ", dataLength)
        
        if (dataLength + startAddress) > 0xffff || startAddress < 0  || dataLength < 0 {
            return "Error"
        }
        
        var output = ""
        
        for m in startAddress ..< startAddress + dataLength {
            
            output = output + String(format: "%02X", ReadAddress(address: UInt16(m)))
            
        }
     
        //print ("String ", output)
     return output
        
    }
    
    func SaveFile(startAddress : Int, userdataLength : Int) -> String {
        
        // This seems to generate the correct address and check digits, hurrah!
        // I think there is an end block which currently is not being generated.
        // This end block is ignored when loading so (shrug)
        
        var dataLength = userdataLength
        
        // Minimum size
        if dataLength < 32
        {
            dataLength = 32
        }
        
        let hexstring = getHexStringFromMemory(startAddress: startAddress, dataLength: dataLength)
        
       
        let l = hexstring.count/2
        
        let s = (Int)(l / 0x18);
        
        var baseAddress = startAddress
        var lineLimit = 0                 // The number of hex pairs to be outout on a given line
     
        var papertape = ""                // Store the complete PTP file.
        
        for i : Int in 0..<s {
            
            var outputLine = ""
            
            if (i == s) {
                lineLimit = (l % 0x18)
                
            } else {
                lineLimit = 0x18
            }
            
            outputLine = ";" + String(format: "%02X",lineLimit).uppercased() + String(format: "%04X",baseAddress).uppercased()
            
            
            let s1 = hexstring.index(hexstring.startIndex, offsetBy: (i * 2 * 0x18) )
            let s2 = hexstring.index(hexstring.startIndex, offsetBy: (i * 2 * 0x18) + (0x18 * 2) )
            outputLine = outputLine + hexstring[s1 ..< s2]
            
            
            var check = 0
            
            for j : Int in stride (from: 1, to: outputLine.count-1, by: 2 ) {
                
                let s3 = outputLine.index(outputLine.startIndex, offsetBy: j)
                let s4 = outputLine.index(outputLine.startIndex, offsetBy: j+2 )
                let s5 = outputLine[s3 ..< s4]
                check = check + Int(s5, radix: 16)!
            }
            
            
            baseAddress = baseAddress + lineLimit
            
            outputLine = outputLine + String(format: "%04X",check).uppercased() + "\r\n"
            
            papertape = papertape + outputLine;
            
            
            
        }
        // End record - zero length, line count twice
        papertape = papertape +  ";00"  + String(format: "%04X",s).uppercased() + String(format: "%04X",s).uppercased() + "\r\n"
        return papertape
        
    }
    
    func LoadPapertapeData(input : String)
    {
        
        LoadPapertapeDataWithOffset(input: input, offset: 0)
        
    }
    
    
   
    func LoadPapertapeDataWithOffset(input : String, offset: UInt16)
    {
        let lines = input.components(separatedBy: ";")
        
        for line in lines
        {
            if line == "" { continue }
            
            var start = line.index(line.startIndex, offsetBy: 0)
            var end = line.index(line.startIndex, offsetBy: 2)
            var range = start..<end
            
            let number_of_bytes = line[range]
            
            start = line.index(line.startIndex, offsetBy: 2)
            end = line.index(line.startIndex, offsetBy: 6)
            range = start..<end
            
            let address = line[range]
            
            start = line.index(line.startIndex, offsetBy: 6)
            end = line.index(line.endIndex, offsetBy: -4)
            range = start..<end
            
            let _ = line[range]
            
            let number_of_bytesD = Int(UInt8((number_of_bytes), radix: 16)!)
            let addressD = Int(UInt16((address), radix: 16)!)
            
            // Is it safe to leave out this test?
            // This tests quits the loading when there aren't bytes to load, typically at the end
            // of a papertape file. HOWEVER, many times papertape programs have multiple blocks of code
            // and so this will happen, and by returning we're quitting before the entire program loads.
            
            if number_of_bytesD == 0
            {
                print("Number of bytes is zero when loading")
                //return
            }
            
            for pair in 0..<number_of_bytesD
            {
                start = line.index(line.startIndex, offsetBy: (6 + (pair * 2)))
                end = line.index(line.startIndex, offsetBy: (8 + (pair * 2)))
                range = start..<end
                let pairH = line[range]
                let pairD = UInt8((pairH), radix: 16)!
                
                //print(String(UInt16(addressD + pair), radix: 16)  , String(pairD, radix: 16) )
                WriteAddress(address: UInt16(addressD + Int(offset) + pair), value: pairD)
                
            }
        }
        
    }
    
