    func GetMemory() -> [UInt8]
    {
        var dump : [UInt8] = []
        
        for i in MEMORY
        {
            dump.append(i.cell)
            //print(String(format: "%02X",i.cell),terminator: "")
        }
        
        return dump
    }
    
    
    func SetMemory(dump : [UInt8])
    {
        var a = 0
        for i in dump
        {
            WriteAddress(address: UInt16(a), value: i)
            a = a + 1
        }
    }
    
    
    
    func LoadFromBundleWithState(name : String, ext : String) ->  [UInt8]
    {
        // let directoryURL = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask)[0]
        let filepath = Bundle.main.path(forResource: name, ofType: ext)
        // let fileURL = URL(fileURLWithPath: "TicTacToe", relativeTo: directoryURL).appendingPathExtension("kim")
        let fileURL = URL(fileURLWithPath: filepath!)
        
        do {
            // Get the saved data - 64Kb of RAM, 7 bytes of registers
            let savedData = try Data(contentsOf: fileURL)
            let status = savedData.endIndex - 7
            let array = [UInt8](savedData)
            SetMemory(dump: array.dropLast(7))
            return [UInt8](array[status...status+6])
            
        } catch {
            // Catch any errors
            //print("Unable to read the file")
            return [0,0,0,0,0,0,0,0]
        }
        
    }
    
    func LoadAppInBinaryForm(filename : String, type : String, address: UInt16)
    {
        
        if let filepath = Bundle.main.path(forResource: filename, ofType: type) {
            do {
                let bData = try Data(contentsOf: URL(fileURLWithPath: filepath))
                let len = (bData.count-1) & 0xffff
                for i in Range(0...len)
                {
                    WriteAddress(address: UInt16(i + Int(address)), value: bData[i])
                    //print(String(format: "%02X",bData[i]),terminator: "")
                }
            } catch {
                //print("Error loading data")
            }
        } else {
            //print("Error finding data")
        }
        
    }
    
    func LoadAppInBinaryWithAddress(filename : String)
    {
        var address : UInt16 = 0
        if let filepath = Bundle.main.path(forResource: filename, ofType: "BIN") {
            do {
                let bData = try Data(contentsOf: URL(fileURLWithPath: filepath))
                for i in Range(0...bData.count-1)
                {
                    if i == 0 { address = UInt16(bData[i]) }
                    if i == 1 { address = address + (UInt16(bData[i])<<8) - 2 }
                    
                    WriteAddress(address: UInt16(i + Int(address)), value: bData[i])
                    //print(String(format: "%02X",bData[i]),terminator: "")
                }
            } catch {
                //print("Error loading data")
            }
        } else {
            //print("Error finding data")
        }
        
    }
    
    
    
    
